const burgerMenu=document.querySelector(".bar"),mobileMenu=document.querySelector(".menu-mobile"),menuExit=document.querySelector(".cross"),question=document.querySelectorAll(".question");function modalToggle(e,o){e.style.display=o}const btnOpenModal=document.querySelectorAll("[data-show-modal]"),modalForm=document.querySelector(".modal");for(let e of btnOpenModal)e.addEventListener("click",()=>{modalToggle(modalForm,"block")});const modalClose=document.querySelectorAll("[data-close-modal]");for(let e of modalClose)e.addEventListener("click",e=>{modalToggle(modalForm,"none")});question.forEach(e=>{e.addEventListener("click",()=>{const o=e.querySelector(".question__answer"),t=o.classList,l=e.querySelector(".question__plus");let n=`${o.scrollHeight}px`,r=45;t.contains("question_active")?(t.remove("question_active"),n=0,r=0):t.add("question_active"),l.style.transform=`rotate(${r}deg)`,o.style.height=n})});const priceSlider=new Swiper(".price-container",{navigation:{prevEl:"#price-prev",nextEl:"#price-next"},loop:!0,slidesPerView:2,simulateTouch:!0,touchRatio:1,touchAngle:45,grabCursor:!0,breakpoints:{344:{slidesPerView:1},1180:{slidesPerView:2,spaceBetween:80}}}),reviewsSlider=new Swiper(".reviews",{navigation:{prevEl:"#reviews-prev",nextEl:"#reviews-next"},simulateTouch:!0,touchRatio:1,touchAngle:45,grabCursor:!0,loop:!0,slidesPerView:1,spaceBetween:150,breakpoints:{1440:{spaceBetween:120},768:{spaceBetween:100},540:{spaceBetween:50}}});burgerMenu.addEventListener("click",()=>{mobileMenu.style.height="100%"}),menuExit.addEventListener("click",()=>{mobileMenu.style.height="0%"});